export const getBookBySlug = (slug: string): Book | undefined => allBooks.find(b => b.slug === slug);
export const getBooksByCategory = (categorySlug: string): Book[] => allBooks.filter(b => b.categorySlug === categorySlug);
export const getBestSellers = (): Book[] => allBooks.filter(b => b.isBestSeller).concat(allBooks.filter(b => b.rating >= 4.7 && !b.isBestSeller)).slice(0, 8);
export const getNewReleases = (): Book[] => allBooks.filter(b => b.isNewRelease || b.year === 2026).slice(0, 10);
export const getOnSaleBooks = (): Book[] => allBooks.filter(b => b.discount && b.discount >= 40).slice(0, 4);
export const searchBooks = (query: string): Book[] => {
  const q = query.toLowerCase();
  return allBooks.filter(b =>
    b.title.toLowerCase().includes(q) ||
    b.author.toLowerCase().includes(q) ||
    b.isbn.includes(q) ||
    b.category.toLowerCase().includes(q)
  );
};
